#include <iostream>
using namespace std;

class Student {
private:
 int roll;
 string name;
public:
 Student(int r = 0, string n = "") {
 roll = r;
 name = n;
 }

 void setData(int r, string n) {
 roll = r;
 name = n;
 }

 void display() {
 cout << "Roll: " << roll << ", Name: " << name << endl;
 }

 ~Student() {
 // Destructor called for cleanup
 }
};

int main() {
 int n = 5;

 // Dynamic allocation
 Student* ptr = new Student[n];

 // Initialize using loop
 for(int i = 0; i < n; i++) {
 ptr[i].setData(i+1, "Student" + to_string(i+1));
 }

 // Display using arrow operator or subscript
 for(int i = 0; i < n; i++) {
 (ptr + i)->display();
 // OR: ptr[i].display();
 }

 // Important: Free memory
 delete[] ptr;

 return 0;
}

#include <iostream>
using namespace std;

class Student {
public:
 int roll;
 string name;

 Student(int r = 0, string n = "") : roll(r), name(n) {}

 void display() {
 cout << roll << ": " << name << endl;
 }
};

// Method 1: Pass array with size
void displayAll(Student arr[], int n) {
 for(int i = 0; i < n; i++) {
 arr[i].display();
 }
}

// Method 2: Pass by reference (preferred)
void displayReference(Student (&arr)[5]) {
 for(int i = 0; i < 5; i++) {
 arr[i].display();
 }
}

int main() {
 Student s[5] = {
 Student(1, "A"), Student(2, "B"), Student(3, "C"),
 Student(4, "D"), Student(5, "E")
 };

 displayAll(s, 5);
 cout << "---" << endl;
 displayReference(s);

 return 0;
}

#include <iostream>
using namespace std;

class Shape {
public:
 virtual void display() = 0;
};

class Circle : public Shape {
 int radius;
public:
 Circle(int r) : radius(r) {}
 void display() {
 cout << "Circle with radius: " << radius << endl;
 }
};

class Rectangle : public Shape {
 int w, h;
public:
 Rectangle(int width, int height) : w(width), h(height) {}
 void display() {
 cout << "Rectangle: " << w << "x" << h << endl;
 }
};

int main() {
 // Array of pointers to base class
 Shape* shapes[3];

 // Each pointer can point to different derived objects
 shapes[0] = new Circle(5);
 shapes[1] = new Rectangle(4, 6);
 shapes[2] = new Circle(10);

 // Polymorphic call
 for(int i = 0; i < 3; i++) {
 shapes[i]->display(); // Arrow operator for pointers
 }

 // Clean up
 for(int i = 0; i < 3; i++) {
 delete shapes[i];
 }

 return 0;
}
